import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif", backgroundColor: '#f0f2f5', minHeight: '100vh' }}>
      
      {/* 1. Hero Section */}
      <header className="hero-section text-white d-flex align-items-center" 
        style={{ 
          background: '#075e54', // WhatsApp Green color
          padding: '40px 0'
        }}>
        <div className="container text-center">
          <h1 className="fw-bold mb-2">Freelance <span style={{ color: '#25d366' }}>Hub</span></h1>
          <p className="opacity-75">Connecting Nashik's talent with the world.</p>
        </div>
      </header>

      {/* 2. WhatsApp Style Profile Section (Top Left Corner) */}
      <section className="py-4">
        <div className="container">
          <h5 className="text-muted mb-3 fw-bold">Recent Profile</h5>
          
          <div className="row">
            <div className="col-md-4">
              {/* This is the WhatsApp style mini-card */}
              <div 
                onClick={() => navigate('/profile/1')}
                className="d-flex align-items-center p-2 bg-white shadow-sm rounded-3 border-start border-4 border-success cursor-pointer"
                style={{ cursor: 'pointer', transition: '0.3s' }}
                onMouseOver={(e) => e.currentTarget.style.backgroundColor = '#f8f9fa'}
                onMouseOut={(e) => e.currentTarget.style.backgroundColor = '#fff'}
              >
                {/* DP (Avatar) in the corner */}
                <div className="position-relative">
                  <img 
                    src="https://freepik.com" 
                    className="rounded-circle border border-2 border-light" 
                    style={{ width: '55px', height: '55px', objectFit: 'cover' }} 
                    alt="DP" 
                  />
                  {/* Online Status Dot like WhatsApp */}
                  <span className="position-absolute bottom-0 end-0 bg-success border border-2 border-white rounded-circle" 
                        style={{ width: '14px', height: '14px' }}></span>
                </div>

                {/* Name and Tagline next to DP */}
                <div className="ms-3 flex-grow-1">
                  <h6 className="mb-0 fw-bold text-dark">Rahul Patil</h6>
                  <p className="mb-0 text-muted small">React Developer • Online</p>
                </div>

                {/* Arrow icon like a chat list */}
                <div className="text-muted pe-2">
                  <small>View →</small>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* 3. Navigation Buttons */}
      <div className="container mt-2">
        <div className="d-flex gap-2">
            <Link to="/services" className="btn btn-sm btn-outline-secondary rounded-pill px-3">Hire Freelancers</Link>
            <Link to="/register" className="btn btn-sm btn-outline-secondary rounded-pill px-3">Join as Freelancer</Link>
        </div>
      </div>

      {/* 4. Feature Highlights */}
      <section className="mt-5 py-4 bg-white border-top">
        <div className="container">
          <div className="row g-3 text-center small">
            <div className="col-4">🛡️ <b>Secure</b></div>
            <div className="col-4">🎓 <b>Verified</b></div>
            <div className="col-4">⚡ <b>Fast</b></div>
          </div>
        </div>
      </section>

    </div>
  );
}

export default Home;
